local LDefenceWarBaseActor = LXImport(".LDefenceWarBaseActor")

local LDefenceWarAtkActor = LxClass("LDefenceWarAtkActor", LDefenceWarBaseActor)
----------------------------------------------------------------
----------------------------------------------------------------

local CS = CS
local ipairs = ipairs
local typeofParticleSystem = typeof(UnityEngine.ParticleSystem)
local typeofAnimator = typeof(UnityEngine.Animator)

function LDefenceWarAtkActor:LDefenceWarAtkActor()
    self._atkName = "attack1"
    self._skillObjList = {}
end

-- 销毁
function LDefenceWarAtkActor:OnDestroy()
    for i, v in ipairs(self._skillObjList) do
        CS.Destroy(v.obj)
    end
    self._skillObjList = {}
end

-- Update
function LDefenceWarAtkActor:Update(dt)
    for i, v in ipairs(self._skillObjList) do
        v.endTime = v.endTime - dt
        if v.endTime <= 0 then
            CS.Destroy(v.obj)
            table.remove(self._skillObjList, i)
            break
        end
    end


    if self._endTime then
        self._endTime = self._endTime - dt
        if self._endTime <= 0 then
            self:StartAtk()
        end
    end
end

-- 初始化动画数据
function LDefenceWarAtkActor:InitAniData()
    if not self._atkTimescale then
        local obj = self:GetObj()
        local aniActor = obj:GetAniActor()
        local aniDuration = aniActor:GetAnimationDuration(self._atkName)
        local objData = obj:GetData()
        local monsterRef = objData:GetMonsterRef()
        self._atkInterval = monsterRef.cd * 0.001 * 0.5

        self._atkTimescale = 1
        if self._atkInterval < aniDuration then
            self._atkTimescale = aniDuration / self._atkInterval
        end

        self._effName      = monsterRef.hitEffect

        local pos          = obj:GetTransform().localPosition
        pos.y              = pos.y - 0.5
        self._hitPos       = pos

        self._effPoolCtrl  = obj:GetCtrl():GetCtrl("EffPool")
        self._hitEffParent = self._effPoolCtrl:GetNodeParent()
        self._layerName    = "UIUp"
    end
end

-- 开始攻击
function LDefenceWarAtkActor:StartAtk()
    if self._obj:GetData():GetHp() <= 0 then
        return
    end

    self._endTime = nil

    self:InitAniData()

    local aniActor = self:GetObj():GetAniActor()
    aniActor:PlayAtk(self._atkName, self._atkTimescale, function() self:OnAtkAniEnd() end)

    self:ShowHitEffect()
    self._obj:StartAtk()
end

-- 攻击结束
function LDefenceWarAtkActor:OnAtkAniEnd()
    self._endTime = self._atkInterval

    local aniActor = self:GetObj():GetAniActor()
    aniActor:PlayIdle()
end

-- 显示命中特效
function LDefenceWarAtkActor:ShowHitEffect()
    self._effPoolCtrl:LoadEffObj(self._effName, function(originObj)
        local obj = CS.InstantObject(originObj)
        local trans = obj.transform
        trans.localPosition = self._hitPos
        local parent = self._effPoolCtrl:GetNodeParent()
        trans:SetParent(parent, false)

        table.insert(self._skillObjList, { obj = obj, trans = trans, endTime = 3 })
    end)
end

-- 暂停
function LDefenceWarAtkActor:OnPauseGame()
    self:UpdateAnimatorSpeed(0)
end

-- 恢复
function LDefenceWarAtkActor:OnResumeGame()
    local speed = self._obj:GetCtrl():GetMgr():GetTimeScale()
    self:UpdateAnimatorSpeed(speed)
end

-- 设置技能速度
function LDefenceWarAtkActor:UpdateAnimatorSpeed(speed)
    for i, v in ipairs(self._skillObjList) do
        local trans = v.trans

        local animatorList = self:GetAnimatorList(trans) or {}
        local animatorLen = #animatorList
        for k = 1, animatorLen do
            local animator = animatorList[k]
            animator.speed = speed
        end

        local particleSystemList = self:GetParticleSystemList(trans) or {}
        local particleSystemLen = #particleSystemList
        for k = 1, particleSystemLen do
            local particleSystem = particleSystemList[k]
            local mainModule = particleSystem.main
            if mainModule then
                mainModule.simulationSpeed = speed
            end
        end
    end
end

-- 获取所有动画
function LDefenceWarAtkActor:GetAnimatorList(trans)
    self._animatorList = self._animatorList or {}
    if not self._animatorList[trans] then
        local cList = trans:GetComponentsInChildren(typeofAnimator, true)
        self._animatorList[trans] = cList:ToTable()
    end
    return self._animatorList[trans]
end

-- 获取所有粒子
function LDefenceWarAtkActor:GetParticleSystemList(trans)
    self._particleSystemList = self._particleSystemList or {}
    if not self._particleSystemList[trans] then
        local cList = trans:GetComponentsInChildren(typeofParticleSystem, true)
        self._particleSystemList[trans] = cList:ToTable()
    end
    return self._particleSystemList[trans]
end

return LDefenceWarAtkActor
